    "domain_rules": [
      {
        "rule": "A customer earns 1 point per dollar spent, rounded down to the nearest integer (floor)",
        "testable_assertion": "earnPoints(customerId, 47.80) returns 47; earnPoints(customerId, 0.99) returns 0"
      },
      {
        "rule": "All points expire after 12 months of account inactivity, defined as no purchase in 12 months",
        "testable_assertion": "An account whose last_purchase_date is more than 12 months ago has all points marked expired when checkExpiry is called"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Two public functions: earnPoints(customerId, purchaseAmount) and checkExpiry(customerId)",
        "implementation_note": "Both live in a single loyalty.ts module. No external dependencies — pure TypeScript."
      },
      {
        "decision": "Use Math.floor for rounding in earnPoints",
        "implementation_note": "Do not use Math.round or Math.trunc. Math.floor matches Bird's 'rounded down to nearest integer' rule and passes both AC1 and AC2."
      },
      {
        "decision": "checkExpiry compares last_purchase_date against a 12-month threshold",
        "implementation_note": "See contradictions_resolved — use calendar-month comparison, not a flat 365-day subtraction, to correctly handle leap years and variable month lengths."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "AC1: Floor rounding on normal purchase",
        "given": "A purchase of $47.80",
        "when": "earnPoints(customerId, 47.80) is called",
        "then": "47 points are earned"
      },
      {
        "criterion": "AC2: Sub-dollar purchase yields zero points",
        "given": "A purchase of $0.99",
        "when": "earnPoints(customerId, 0.99) is called",
        "then": "0 points are earned"
      },
      {
        "criterion": "AC3: Points expire after 12 months of inactivity",
        "given": "An account with no purchase in the last 12 months",
        "when": "checkExpiry(customerId) is called",
        "then": "All points on the account are marked expired"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "account inactivity",
        "technical_term": "last_purchase_date threshold check",
        "definition": "An account is 'inactive' when the elapsed time since last_purchase_date exceeds 12 calendar months. This is the sole trigger for point expiration."
      },
      {
        "domain_term": "points are marked expired",
        "technical_term": "expiry status flag or removal",
        "definition": "Bird says 'marked expired' — Shaq needs to decide the representation (boolean flag, status enum, or deletion). If uncertain, use a status field so expiry is auditable."
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "Bird specifies '12 months of inactivity' but MJ specifies 'current date minus 365 days'. 12 calendar months != 365 days (leap years, variable month lengths).",
        "resolution": "Bird is the domain authority. Use 12 calendar months (e.g., subtract 12 from the month component or use a date library equivalent), not a flat 365-day subtraction. Example: if today is 2026-03-24, the threshold date is 2025-03-24, regardless of leap year math."
      }
    ],
    "open_questions": [
