    "assumptions": [
      "Bird's domain rules take precedence over MJ's technical spec where they conflict (12 months vs 365 days)",
      "The module is intended for server-side use where Date handling is straightforward",
      "Edge cases like negative purchase amounts are not explicitly handled by either spec — flagged as open question"
    ]
  }
}

